import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class IndentationRuleParenthesizedInIfTest {
    private val indentationRuleAssertThat =
        assertThatRule { IndentationRule() }

    @Test
    fun `Issue 967 - Given a parenthesized expression in if block with ktlint_official code style`() {
        val code =
            """
            val pass = if (condition1) {
                (
                    condition2
                )
            } else {
                condition3
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Issue 967 - Given a multiline if condition with parenthesized expression in then block with ktlint_official code style`() {
        val code =
            """
            if (
                condition1
            ) {
                (
                    condition2
                )
            } else {
                condition3
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Issue 967 - Given a parenthesized expression in else block with ktlint_official code style`() {
        val code =
            """
            val pass = if (condition1) {
                foo()
            } else {
                (
                    condition2
                )
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Issue 967 - Given nested if statements with parenthesized expressions with ktlint_official code style`() {
        val code =
            """
            fun foo() {
                if (condition1) {
                    val x = if (condition2) {
                        (
                            condition3
                        )
                    } else {
                        (
                            condition4
                        )
                    }
                }
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Issue 967 - Parenthesized expression in if condition should still be indented properly`() {
        val code =
            """
            if (
                (
                    condition1
                )
            ) {
                foo()
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official)
            .hasNoLintViolations()
    }
}
